```json
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://api.saas-billing.com/schemas/billing-system-v1.json",
  "title": "Multi-Tenant SaaS Billing System Schema",
  "description": "JSON schema for a comprehensive multi-tenant SaaS billing system supporting usage-based and seat-based pricing models",
  "type": "object",
  "properties": {
    "version": {
      "type": "string",
      "const": "1.0",
      "description": "Schema version for backward compatibility"
    },
    "entities": {
      "type": "object",
      "properties": {
        "organizations": {
          "type": "array",
          "items": { "$ref": "#/definitions/Organization" }
        },
        "customers": {
          "type": "array", 
          "items": { "$ref": "#/definitions/Customer" }
        },
        "plans": {
          "type": "array",
          "items": { "$ref": "#/definitions/Plan" }
        },
        "subscriptions": {
          "type": "array",
          "items": { "$ref": "#/definitions/Subscription" }
        },
        "invoices": {
          "type": "array",
          "items": { "$ref": "#/definitions/Invoice" }
        },
        "usage_records": {
          "type": "array",
          "items": { "$ref": "#/definitions/UsageRecord" }
        },
        "payment_methods": {
          "type": "array",
          "items": { "$ref": "#/definitions/PaymentMethod" }
        }
      },
      "additionalProperties": false
    }
  },
  "required": ["version", "entities"],
  "additionalProperties": false,

  "definitions": {
    "Money": {
      "type": "object",
      "description": "Monetary amount with currency",
      "properties": {
        "amount": {
          "type": "integer",
          "minimum": 0,
          "description": "Amount in smallest currency unit (cents for USD)"
        },
        "currency": {
          "type": "string",
          "pattern": "^[A-Z]{3}$",
          "description": "ISO 4217 currency code"
        }
      },
      "required": ["amount", "currency"],
      "additionalProperties": false
    },

    "Organization": {
      "type": "object",
      "description": "Tenant organization in multi-tenant system",
      "properties": {
        "id": {
          "type": "string",
          "pattern": "^org_[a-zA-Z0-9]{16}$"
        },
        "name": {
          "type": "string",
          "minLength": 1,
          "maxLength": 255
        },
        "created_at": {
          "type": "string",
          "format": "date-time"
        },
        "updated_at": {
          "type": "string",
          "format": "date-time"
        },
        "metadata": {
          "type": "object",
          "additionalProperties": true,
          "description": "Extensible metadata for custom fields"
        }
      },
      "required": ["id", "name", "created_at"],
      "additionalProperties": false
    },

    "Customer": {
      "type": "object",
      "description": "Customer entity with billing information",
      "properties": {
        "id": {
          "type": "string",
          "pattern": "^cus_[a-zA-Z0-9]{16}$"
        },
        "organization_id": {
          "type": "string",
          "pattern": "^org_[a-zA-Z0-9]{16}$"
        },
        "name": {
          "type": "string",
          "minLength": 1,
          "maxLength": 255
        },
        "email": {
          "type": "string",
          "format": "email"
        },
        "billing_address": {
          "$ref": "#/definitions/Address"
        },
        "tax_ids": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "type": {
                "type": "string",
                "enum": ["vat", "gst", "ein", "ssn"]
              },
              "value": {
                "type": "string"
              }
            },
            "required": ["type", "value"],
            "additionalProperties": false
          }
        },
        "created_at": {
          "type": "string",
          "format": "date-time"
        },
        "updated_at": {
          "type": "string",
          "format": "date-time"
        },
        "metadata": {
          "type": "object",
          "additionalProperties": true
        }
      },
      "required": ["id", "organization_id", "name", "email", "created_at"],
      "additionalProperties": false
    },

    "Address": {
      "type": "object",
      "properties": {
        "line1": { "type": "string" },
        "line2": { "type": "string" },
        "city": { "type": "string" },
        "state": { "type": "string" },
        "postal_code": { "type": "string" },
        "country": {
          "type": "string",
          "pattern": "^[A-Z]{2}$",
          "description": "ISO 3166-1 alpha-2 country code"
        }
      },
      "required": ["line1", "city", "country"],
      "additionalProperties": false
    },

    "Plan": {
      "type": "object",
      "description": "Billing plan supporting hybrid pricing models",
      "properties": {
        "id": {
          "type": "string",
          "pattern": "^plan_[a-zA-Z0-9]{16}$"
        },
        "name": {
          "type": "string",
          "minLength": 1,
          "maxLength": 255
        },
        "description": {
          "type": "string",
          "maxLength": 1000
        },
        "pricing_model": {
          "$ref": "#/definitions/PricingModel"
        },
        "billing_interval": {
          "type": "string",
          "enum": ["day", "week", "month", "quarter", "year"]
        },
        "billing_interval_count": {
          "type": "integer",
          "minimum": 1,
          "default": 1,
          "description": "Number of intervals between billings"
        },
        "trial_period_days": {
          "type": ["integer", "null"],
          "minimum": 0,
          "maximum": 365
        },
        "active": {
          "type": "boolean",
          "default": true
        },
        "created_at": {
          "type": "string", 
          "format": "date-time"
        },
        "updated_at": {
          "type": "string",
          "format": "date-time"
        },
        "metadata": {
          "type": "object",
          "additionalProperties": true
        }
      },
      "required": ["id", "name", "pricing_model", "billing_interval", "created_at"],
      "additionalProperties": false
    },

    "PricingModel": {
      "type": "object",
      "description": "Hybrid pricing model supporting both seat-based and usage-based pricing",
      "properties": {
        "type": {
          "type": "string",
          "enum": ["seat_based", "usage_based", "hybrid"],
          "description": "Type of pricing model"
        },
        "seat_price": {
          "anyOf": [
            { "$ref": "#/definitions/Money" },
            { "type": "null" }
          ],
          "description": "Fixed price per seat/user (required for seat_based and hybrid)"
        },
        "minimum_seats": {
          "type": ["integer", "null"],
          "minimum": 0,
          "description": "Minimum number of seats to charge for"
        },
        "included_seats": {
          "type": ["integer", "null"], 
          "minimum": 0,
          "description": "Number of seats included in base price"
        },
        "metered_dimensions": {
          "type": "array",
          "description": "Dynamic usage-based pricing dimensions",
          "items": {
            "$ref": "#/definitions/MeteredDimension"
          }
        },
        "base_fee": {
          "anyOf": [
            { "$ref": "#/definitions/Money" },
            { "type": "null" }
          ],
          "description": "Fixed base fee charged regardless of usage"
        }
      },
      "required": ["type"],
      "allOf": [
        {
          "if": {
            "properties": { "type": { "enum": ["seat_based", "hybrid"] } }
          },
          "then": {
            "required": ["seat_price"]
          }
        },
        {
          "if": {
            "properties": { "type": { "enum": ["usage_based", "hybrid"] } }
          },
          "then": {
            "required": ["metered_dimensions"],
            "properties": {
              "metered_dimensions": {
                "minItems": 1
              }
            }
          }
        }
      ],
      "additionalProperties": false
    },

    "MeteredDimension": {
      "type": "object",
      "description": "Extensible metered dimension for usage tracking",
      "properties": {
        "id": {
          "type": "string",
          "pattern": "^dim_[a-zA-Z0-9_]{1,50}$",
          "description": "Unique dimension identifier"
        },
        "name": {
          "type": "string",
          "minLength": 1,
          "maxLength": 255,
          "description": "Human-readable dimension name"
        },
        "unit": {
          "type": "string",
          "minLength": 1,
          "maxLength": 50,
          "description": "Unit of measurement (e.g., 'requests', 'GB', 'users')"
        },
        "aggregation": {
          "type": "string",
          "enum": ["sum", "max", "last_value", "unique_count"],
          "description": "How to aggregate usage events"
        },
        "tiers": {
          "type": "array",
          "description": "Tiered pricing structure",
          "items": {
            "$ref": "#/definitions/PricingTier"
          },
          "minItems": 1
        }
      },
      "required": ["id", "name", "unit", "aggregation", "tiers"],
      "additionalProperties": false
    },

    "PricingTier": {
      "type": "object",
      "description": "Individual pricing tier for graduated or volume pricing",
      "properties": {
        "up_to": {
          "anyOf": [
            { "type": "integer", "minimum": 1 },
            { "type": "null" }
          ],
          "description": "Upper limit for this tier (null for infinity)"
        },
        "unit_price": {
          "anyOf": [
            { "$ref": "#/definitions/Money" },
            { "type": "null" }
          ],
          "description": "Price per unit in this tier"
        },
        "flat_fee": {
          "anyOf": [
            { "$ref": "#/definitions/Money" },
            { "type": "null" }
          ],
          "description": "Fixed fee for this tier"
        }
      },
      "anyOf": [
        { "required": ["unit_price"] },
        { "required": ["flat_fee"] }
      ],
      "additionalProperties": false
    },

    "Subscription": {
      "type": "object",
      "description": "Customer subscription with lifecycle management",
      "properties": {
        "id": {
          "type": "string",
          "pattern": "^sub_[a-zA-Z0-9]{16}$"
        },
        "customer_id": {
          "type": "string",
          "pattern": "^cus_[a-zA-Z0-9]{16}$"
        },
        "plan_id": {
          "type": "string", 
          "pattern": "^plan_[a-zA-Z0-9]{16}$"
        },
