});

// Add connection pool monitoring
pool.on('connect', (client) => {
  console.log(`[${new Date().toISOString()}] New client connected. Total: ${pool.totalCount}, Idle: ${pool.idleCount}, Waiting: ${pool.waitingCount}`);
});

pool.on('acquire', (client) => {
  console.log(`[${new Date().toISOString()}] Client acquired. Total: ${pool.totalCount}, Idle: ${pool.idleCount}, Waiting: ${pool.waitingCount}`);
});

pool.on('remove', (client) => {
  console.log(`[${new Date().toISOString()}] Client removed. Total: ${pool.totalCount}, Idle: ${pool.idleCount}, Waiting: ${pool.waitingCount}`);
});

pool.on('error', (err, client) => {
  console.error(`[${new Date().toISOString()}] Pool error:`, err);
});

module.exports = pool;
```

### Add Request-Level Logging
```javascript
// middleware/logger.js
const crypto = require('crypto');

function requestLogger(req, res, next) {
  req.requestId = crypto.randomUUID();
  req.startTime = Date.now();

  console.log(`[${new Date().toISOString()}] [${req.requestId}] ${req.method} ${req.path} - START`);

  const originalSend = res.send;
  res.send = function(data) {
    const duration = Date.now() - req.startTime;
    console.log(`[${new Date().toISOString()}] [${req.requestId}] ${req.method} ${req.path} - ${res.statusCode} (${duration}ms)`);
    originalSend.call(this, data);
  };

  next();
}

module.exports = requestLogger;
```

## Step 3: Identify the Problematic Code

### Common Race Condition Pattern (PROBLEMATIC)
```javascript
// routes/users.js - BEFORE (with race condition)
const express = require('express');
const pool = require('../db');
const router = express.Router();

let userCounter = 0; // ❌ Shared mutable state

router.post('/users', async (req, res) => {
  const client = await pool.connect();

  try {
    // ❌ Race condition: multiple requests can read the same counter value
    userCounter++;
    const userId = userCounter;

    // ❌ Another race condition: non-atomic database operations
    const existingUser = await client.query(
      'SELECT id FROM users WHERE email = $1', 
      [req.body.email]
    );

    if (existingUser.rows.length > 0) {
      return res.status(400).json({ error: 'User already exists' });
    }

    // ❌ Between the check above and insert below, another request 
    // could insert the same email
    const result = await client.query(
      'INSERT INTO users (id, name, email) VALUES ($1, $2, $3) RETURNING *',
      [userId, req.body.name, req.body.email]
    );

    res.json(result.rows[0]);
  } catch (error) {
    console.error(`[${req.requestId}] Database error:`, error);
    res.status(500).json({ error: 'Internal server error' });
  } finally {
    client.release(); // ❌ Client might not be released if error occurs before this
  }
});
```

## Step 4: Add Detailed Error Tracking

### Enhanced Error Handling
```javascript
// middleware/errorHandler.js
function errorHandler(err, req, res, next) {
  const errorId = crypto.randomUUID();

  console.error(`[${new Date().toISOString()}] [${req.requestId}] [ERROR-${errorId}]`, {
    message: err.message,
    stack: err.stack,
    code: err.code,
    constraint: err.constraint,
    detail: err.detail,
    url: req.url,
    method: req.method,
    body: req.body,
    headers: req.headers
  });

  // PostgreSQL specific error codes
  if (err.code === '23505') { // unique_violation
    return res.status(409).json({ 
      error: 'Resource already exists',
      errorId 
    });
  }

  if (err.code === '23503') { // foreign_key_violation
    return res.status(400).json({ 
      error: 'Invalid reference',
      errorId 
    });
  }

  res.status(500).json({ 
    error: 'Internal server error',
    errorId 
  });
}

module.exports = errorHandler;
```

## Step 5: Implement Database Connection Debugging

### Connection Pool Wrapper with Debugging
```javascript
// db/debugPool.js
const pool = require('./db');

class DebugPool {
  constructor(originalPool) {
    this.pool = originalPool;
    this.activeConnections = new Map();
  }

  async connect() {
    const connectionId = crypto.randomUUID();
    const startTime = Date.now();

    console.log(`[${new Date().toISOString()}] [CONN-${connectionId}] Requesting connection...`);

    try {
      const client = await this.pool.connect();
      const acquireTime = Date.now() - startTime;

      console.log(`[${new Date().toISOString()}] [CONN-${connectionId}] Connection acquired (${acquireTime}ms)`);

      // Wrap the release method
      const originalRelease = client.release.bind(client);
      client.release = (err) => {
        const releaseTime = Date.now();
        const totalTime = releaseTime - startTime;
        console.log(`[${new Date().toISOString()}] [CONN-${connectionId}] Connection released (held for ${totalTime}ms)`);
        this.activeConnections.delete(connectionId);
        return originalRelease(err);
      };

      this.activeConnections.set(connectionId, {
        acquiredAt: new Date(),
        client
      });

      return client;
    } catch (error) {
      console.error(`[${new Date().toISOString()}] [CONN-${connectionId}] Connection failed:`, error);
      throw error;
    }
  }

  getActiveConnections() {
    return Array.from(this.activeConnections.entries()).map(([id, info]) => ({
      id,
      acquiredAt: info.acquiredAt,
      duration: Date.now() - info.acquiredAt.getTime()
    }));
  }
}

module.exports = new DebugPool(pool);
```

## Step 6: Fix the Race Conditions

### Corrected Implementation
```javascript
// routes/users.js - AFTER (race conditions fixed)
const express = require('express');
const pool = require('../db/debugPool');
const router = express.Router();

router.post('/users', async (req, res, next) => {
  let client;

  try {
    client = await pool.connect();

    // ✅ Use database transaction for atomicity
    await client.query('BEGIN');

    // ✅ Use database sequence instead of application counter
    // ✅ Handle unique constraint at database level with proper error handling
    const result = await client.query(`
      INSERT INTO users (name, email, created_at) 
      VALUES ($1, $2, NOW()) 
      RETURNING *
    `, [req.body.name, req.body.email]);

    await client.query('COMMIT');

    console.log(`[${new Date().toISOString()}] [${req.requestId}] User created successfully`);
    res.status(201).json(result.rows[0]);

  } catch (error) {
    // ✅ Rollback transaction on error
    if (client) {
      try {
        await client.query('ROLLBACK');
      } catch (rollbackError) {
        console.error(`[${req.requestId}] Rollback failed:`, rollbackError);
      }
    }

    next(error); // Pass to error handler
  } finally {
    // ✅ Always release client
    if (client) {
      client.release();
    }
  }
});

// ✅ Alternative approach using pool.query (automatically handles connection)
router.post('/users-simple', async (req, res, next) => {
  try {
    const result = await pool.query(`
      INSERT INTO users (name, email, created_at) 
      VALUES ($1, $2, NOW()) 
      RETURNING *
    `, [req.body.name, req.body.email]);

    res.status(201).json(result.rows[0]);
  } catch (error) {
    next(error);
  }
});
```

