import { UserService } from './services/UserService';

export const resolvers: Resolvers = {
  User: {
    __resolveReference: async (user: { id: string }, { dataSources, userLoader }) => {
      return userLoader.load(user.id);
    },

    fullName: (parent) => `${parent.firstName} ${parent.lastName}`,

    isActive: (parent) => {
      const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
      return parent.lastLoginAt > thirtyDaysAgo;
    },
  },

  UserProfile: {
    __resolveReference: async (profile: { userId: string }, { userProfileLoader }) => {
      return userProfileLoader.load(profile.userId);
