    user: async (parent, _, { userLoader }) => {
      return userLoader.load(parent.userId);
    },
  },

  Query: {
    me: async (_, __, { user, userLoader }) => {
      if (!user) throw new Error('Not authenticated');
      return userLoader.load(user.id);
