        throw new Error('Insufficient permissions');
      }
      return dataSources.userService.getUsers(args);
    },
  },

  Mutation: {
    register: async (_, { input }, { dataSources }) => {
      return dataSources.userService.register(input);
    },

    login: async (_, { input }, { dataSources }) => {
      return dataSources.userService.login(input);
    },

    updateProfile: async (_, { input }, { user, dataSources }) => {
