```javascript
import DataLoader from 'dataloader';
import { createHash } from 'crypto';

class UsersSubgraphResolvers {
  constructor(db, redis) {
    this.db = db;
    this.redis = redis;
  }

  createDataLoaders() {
    return {
      userLoader: new DataLoader(async (userIds) => {
        const cacheKey = `users:batch:${this.hashKeys(userIds)}`;
        const cached = await this.redis.get(cacheKey);

        if (cached) {
          return JSON.parse(cached);
        }

        const users = await this.db.users.findMany({
          where: { id: { in: userIds } },
        });

        const userMap = new Map(users.map(u => [u.id, u]));
        const result = userIds.map(id => userMap.get(id) || null);

        await this.redis.setex(cacheKey, 300, JSON.stringify(result));
        return result;
      }, { cache: false }), // Per-request caching only
    };
  }

  hashKeys(keys) {
    return createHash('md5').update(keys.sort().join(':')).digest('hex');
  }

  getResolvers() {
    return {
      Query: {
        me: async (_, __, { user, dataSources }) => {
          if (!user) throw new Error('Authentication required');
          return dataSources.userLoader.load(user.id);
        },

        users: async (_, { first = 20, after }, { user, dataSources }) => {
          if (user.role !== 'ADMIN') {
            throw new Error('Admin access required');
          }

          const offset = after ? parseInt(Buffer.from(after, 'base64').toString()) : 0;
          const users = await this.db.users.findMany({
            take: first + 1,
            skip: offset,
            orderBy: { createdAt: 'desc' },
          });

          const hasNextPage = users.length > first;
          if (hasNextPage) users.pop();

          return {
            edges: users.map((user, index) => ({
              node: user,
              cursor: Buffer.from((offset + index).toString()).toString('base64'),
            })),
            pageInfo: {
              hasNextPage,
              hasPreviousPage: offset > 0,
              startCursor: users.length > 0 ? Buffer.from(offset.toString()).toString('base64') : null,
              endCursor: users.length > 0 ? Buffer.from((offset + users.length - 1).toString()).toString('base64') : null,
            },
            totalCount: await this.db.users.count(),
          };
        },
      },

      Mutation: {
        updateProfile: async (_, { input }, { user, dataSources }) => {
          try {
            const updatedUser = await this.db.users.update({
              where: { id: user.id },
              data: input,
            });

            // Invalidate cache
            await this.redis.del(`user:${user.id}`);
            return updatedUser;
          } catch (error) {
            if (error.code === 'P2002') {
              return {
                __typename: 'ValidationError',
                message: 'Email already exists',
                field: 'email',
              };
            }
            throw error;
          }
        },
      },

      User: {
        __resolveReference: async (reference, { dataSources }) => {
          try {
            return await dataSources.userLoader.load(reference.id);
          } catch (error) {
            console.error('Failed to resolve user reference:', error);
            return null; // Consistent null return for missing entities
          }
        },

        email: async (user, _, { user: currentUser }) => {
          // Field-level authorization with ownership check
          if (currentUser?.role === 'ADMIN' || currentUser?.id === user.id) {
            return user.email;
          }
          throw new Error('Unauthorized to view email');
        },
      },

      UpdateProfileResult: {
        __resolveType: (obj) => {
          if (obj.id) return 'User';
          if (obj.field) return 'ValidationError';
          return 'NotFoundError';
        },
      },
    };
  }
}
