```javascript
import DataLoader from 'dataloader';

class OrdersSubgraphResolvers {
  constructor(db, redis, productService, paymentService) {
    this.db = db;
    this.redis = redis;
    this.productService = productService;
    this.paymentService = paymentService;
  }

  createDataLoaders() {
    return {
      orderLoader: new DataLoader(async (orderIds) => {
        const orders = await this.db.orders.findMany({
          where: { id: { in: orderIds } },
          include: { items: true, shippingAddress: true, billingAddress: true },
        });
        const orderMap = new Map(orders.map(o => [o.id, o]));
        return orderIds.map(id => orderMap.get(id) || null);
      }),

      orderItemsByOrderLoader: new DataLoader(async (orderIds) => {
        const orderItems = await this.db.orderItems.findMany({
          where: { orderId: { in: orderIds } },
        });
        const itemsByOrder = new Map();
        orderIds.forEach(id => itemsByOrder.set(id, []));
        orderItems.forEach(item => {
          const items = itemsByOrder.get(item.orderId);
          items.push(item);
        });
        return orderIds.map(id => itemsByOrder.get(id) || []);
      }),

      ordersByUserLoader: new DataLoader(async (userIds) => {
        const orders = await this.db.orders.findMany({
          where: { userId: { in: userIds } },
          orderBy: { createdAt: 'desc' },
        });
        const ordersByUser = new Map();
        userIds.forEach(id => ordersByUser.set(id, []));
        orders.forEach(order => {
          const userOrders = ordersByUser.get(order.userId);
          userOrders.push(order);
        });
        return userIds.map(id => ordersByUser.get(id) || []);
      }),

      cartLoader: new DataLoader(async (userIds) => {
        const carts = await this.db.carts.findMany({
          where: { userId: { in: userIds } },
          include: { items: true },
        });
        const cartMap = new Map(carts.map(c => [c.userId, c]));
        return userIds.map(id => cartMap.get(id) || null);
      }),
    };
  }

  getResolvers() {
    return {
      Query: {
        order: async (_, { id }, { user, dataSources }) => {
          try {
            const order = await dataSources.orderLoader.load(id);
            if (!order || (user.role !== 'ADMIN' && order.userId !== user.id)) {
              return null; // Consistent null return for unauthorized/missing entities
            }
            return order;
          } catch (error) {
            console.error('Failed to load order:', error);
            return null;
          }
        },

        orders: async (_, { first = 20, after }, { user, dataSources }) => {
          const orders = await dataSources.ordersByUserLoader.load(user.id);
          const offset = after ? parseInt(Buffer.from(after, 'base64').toString()) : 0;
          const slice = orders.slice(offset, offset + first);

          return {
            edges: slice.map((order, index) => ({
              node: order,
              cursor: Buffer.from((offset + index).toString()).toString('base64'),
            })),
            pageInfo: {
              hasNextPage: orders.length > offset + first,
              hasPreviousPage: offset > 0,
              startCursor: slice.length > 0 ? Buffer.from(offset.toString()).toString('base64') : null,
              endCursor: slice.length > 0 ? Buffer.from((offset + slice.length - 1).toString()).toString('base64') : null,
            },
            totalCount: orders.length,
          };
        },
      },

      Order: {
        __resolveReference: async (reference, { dataSources }) => {
          try {
            return await dataSources.orderLoader.load(reference.id);
          } catch (error) {
            console.error('Failed to resolve order reference:', error);
            return null;
          }
        },

        items: async (order, _, { dataSources }) => {
          return dataSources.orderItemsByOrderLoader.load(order.id);
        },

        user: (order) => ({ __typename: 'User', id: order.userId }),
      },

      User: {
        orders: async (user, { first = 10, after }, { dataSources }) => {
          const orders = await dataSources.ordersByUserLoader.load(user.id);
          const offset = after ? parseInt(Buffer.from(after, 'base64').toString()) : 0;
          const slice = orders.slice(offset, offset + first);

          return {
            edges: slice.map((order, index) => ({
              node: order,
              cursor: Buffer.from((offset + index).toString()).toString('base64'),
            })),
            pageInfo: {
              hasNextPage: orders.length > offset + first,
              hasPreviousPage: offset > 0,
              startCursor: slice.length > 0 ? Buffer.from(offset.toString()).toString('base64') : null,
              endCursor: slice.length > 0 ? Buffer.from((offset + slice.length - 1).toString()).toString('base64') : null,
            },
            totalCount: orders.length,
          };
        },

        cart: async (user, _, { dataSources }) => {
          return dataSources.cartLoader.load(user.id);
        },

        __resolveReference: async (reference, { dataSources }) => {
          return { id: reference.id }; // Stub - full resolution handled by users subgraph
        },
      },

      Product: {
        orderItems: async (product, _, { dataSources }) => {
          const orderItems = await this.db.orderItems.findMany({
            where: { productId: product.id },
          });
          return orderItems;
        },

        __resolveReference: async (reference, { dataSources }) => {
          return { id: reference.id, sku: reference.sku }; // Stub - full resolution handled by products subgraph
        },
      },

      OrderItem: {
        __resolveReference: async (reference, { dataSources }) => {
          try {
            const orderItem = await this.db.orderItems.findUnique({
              where: { id: reference.id },
            });
            return orderItem || null;
          } catch (error) {
            console.error('Failed to resolve order item reference:', error);
            return null;
          }
        },

        product: (orderItem) => ({ __typename: 'Product', id: orderItem.productId }),
        order: async (orderItem, _, { dataSources }) => {
          return dataSources.orderLoader.load(orderItem.orderId);
        },
      },

      Cart: {
        __resolveReference: async (reference, { dataSources }) => {
          try {
            return await dataSources.cartLoader.load(reference.userId);
          } catch (error) {
            console.error('Failed to resolve cart reference:', error);
            return null;
          }
        },

        user: (cart) => ({ __typename: 'User', id: cart.userId }),

        subtotal: (cart) => {
          return cart.items.reduce((sum, item) => sum + (item.quantity * item.unitPrice), 0);
        },

        itemCount: (cart) => {
          return cart.items.reduce((sum, item) => sum + item.quantity, 0);
        },
      },

      Mutation: {
        createOrder: async (_, { input }, { user, dataSources }) => {
          try {
            const cart = await dataSources.cartLoader.load(user.id);
            if (!cart || cart.items.length === 0) {
              return {
                __typename: 'ValidationError',
                message: 'Cart is empty',
                field: 'cart',
              };
            }

            // Check stock availability for all items
            const stockCheck = await this.productService.checkStock(
              cart.items.map(item => ({ productId: item.productId, quantity: item.quantity }))
            );

            if (!stockCheck.available) {
              return {
                __typename: 'InsufficientStockError',
                message: stockCheck.message,
                requested: stockCheck.requested,
                available: stockCheck.available,
              };
            }

            // Create order
            const order = await this.db.orders.create({
              data: {
                userId: user.id,
                orderNumber: await this.generateOrderNumber(),
                items: {
                  create: cart.items.map(item => ({
                    productId: item.productId,
                    quantity: item.quantity,
                    unitPrice: item.unitPrice,
                    totalPrice: item.quantity * item.unitPrice,
                  })),
                },
                status: 'PENDING',
                subtotal: cart.subtotal,
                tax: this.calculateTax(cart.subtotal),
                shipping: this.calculateShipping(cart.items),
                total: cart.subtotal + this.calculateTax(cart.subtotal) + this.calculateShipping(cart.items),
                shippingAddress: { create: input.shippingAddress },
                billingAddress: { create: input.billingAddress },
              },
              include: { items: true, shippingAddress: true, billingAddress: true },
            });

            // Reserve inventory
            await this.productService.reserveStock(
              cart.items.map(item => ({ productId: item.productId, quantity: item.quantity }))
            );

            // Clear cart
            await this.db.cartItems.deleteMany({
              where: { cartId: cart.id },
            });

            // Invalidate cache
            await dataSources.cartLoader.clear(user.id);
            await dataSources.ordersByUserLoader.clear(user.id);

            return order;
          } catch (error) {
            return {
              __typename: 'PaymentFailedError',
              message: error.message,
              code: error.code || 'UNKNOWN',
            };
          }
        },
      },
    };
  }

  async generateOrderNumber() {
    const timestamp = Date.now().toString(36).toUpperCase();
    const random = Math.random().toString(36).substring(2, 8).toUpperCase();
    return `ORD-${timestamp}-${random}`;
  }

  calculateTax(subtotal) {
    return subtotal * 0.08; // 8% tax rate
  }

  calculateShipping(items) {
    const itemCount = items.reduce((sum, item) => sum + item.quantity, 0);
    return itemCount * 2.50; // $2.50 per item
  }
