// Custom error types for the cache
#[derive(Debug, Clone)]
pub enum CacheError {
    KeyNotFound,
    Expired,
    CapacityExceeded,
    InvalidTtl,
    CachePoisoned,
    BackgroundTaskFailed,
}

impl fmt::Display for CacheError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            CacheError::KeyNotFound => write!(f, "Key not found in cache"),
            CacheError::Expired => write!(f, "Cache entry has expired"),
            CacheError::CapacityExceeded => write!(f, "Cache capacity exceeded"),
            CacheError::InvalidTtl => write!(f, "Invalid TTL value"),
            CacheError::CachePoisoned => write!(f, "Cache lock is poisoned"),
            CacheError::BackgroundTaskFailed => write!(f, "Background eviction task failed"),
        }
    }
}

impl std::error::Error for CacheError {}

