/// Custom error types for cache operations
#[derive(Debug)]
pub enum CacheError {
    /// Lock was poisoned by a panicked thread
    PoisonedLock(String),
    /// Cache capacity exceeded or invalid
    InvalidCapacity,
    /// Background thread failed to start
    ThreadError(String),
    /// Memory allocation failure
    AllocationError,
    /// Cache operation timed out
    Timeout,
}

impl fmt::Display for CacheError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            CacheError::PoisonedLock(msg) => write!(f, "Lock poisoned: {}", msg),
            CacheError::InvalidCapacity => write!(f, "Invalid cache capacity"),
            CacheError::ThreadError(msg) => write!(f, "Thread error: {}", msg),
            CacheError::AllocationError => write!(f, "Memory allocation failed"),
            CacheError::Timeout => write!(f, "Operation timed out"),
        }
    }
}

impl StdError for CacheError {}

impl<T> From<PoisonError<T>> for CacheError {
    fn from(err: PoisonError<T>) -> Self {
        CacheError::PoisonedLock(err.to_string())
    }
}

/// Result type alias for cache operations
pub type CacheResult<T> = Result<T, CacheError>;

/// A node in the doubly-linked list for O(1) LRU operations
struct Node<K, V> {
    key: K,
    value: V,
    expires_at: Option<Instant>,
    prev: Option<NonNull<Node<K, V>>>,
    next: Option<NonNull<Node<K, V>>>,
}

impl<K, V> Node<K, V> {
    fn new(key: K, value: V, ttl: Option<Duration>) -> Self {
        let expires_at = ttl.map(|duration| Instant::now() + duration);
        Self {
            key,
            value,
            expires_at,
            prev: None,
            next: None,
        }
    }

    fn is_expired(&self) -> bool {
        self.expires_at.map_or(false, |expiry| Instant::now() >= expiry)
    }
}

/// Internal cache data protected by RwLock
struct CacheInner<K, V> {
    map: HashMap<K, NonNull<Node<K, V>>>,
    head: Option<NonNull<Node<K, V>>>,
    tail: Option<NonNull<Node<K, V>>>,
    capacity: usize,
    default_ttl: Option<Duration>,
}

impl<K, V> CacheInner<K, V>
where
    K: Clone + Eq + Hash,
{
    fn new(capacity: usize, default_ttl: Option<Duration>) -> Self {
        Self {
            map: HashMap::with_capacity(capacity),
            head: None,
            tail: None,
            capacity,
            default_ttl,
        }
    }

    /// Check if key exists and is not expired (read-only operation)
    fn contains_key_and_not_expired(&self, key: &K) -> bool {
        self.map.get(key).map_or(false, |&node| {
            unsafe {
                let node_ref = node.as_ref();
                !node_ref.is_expired()
            }
        })
    }

    /// Get value without promoting (read-only for checking)
    fn peek(&self, key: &K) -> Option<V> 
    where
        V: Clone,
    {
        self.map.get(key).and_then(|&node| {
            unsafe {
                let node_ref = node.as_ref();
                if node_ref.is_expired() {
                    None
                } else {
                    Some(node_ref.value.clone())
                }
            }
        })
    }

    /// Move node to front (most recently used position)
    /// Correctly implements LRU access promotion by moving accessed entries to head
    unsafe fn move_to_front(&mut self, mut node: NonNull<Node<K, V>>) {
        let node_ref = node.as_mut();

        // If already at head, nothing to do
        if Some(node) == self.head {
            return;
        }

        // Remove from current position
        self.remove_from_list(node);

        // Add to front - promoting to most recently used position
        self.add_to_front(node);
    }

    /// Remove node from its current position in the list
    unsafe fn remove_from_list(&mut self, mut node: NonNull<Node<K, V>>) {
        let node_ref = node.as_mut();

        match node_ref.prev {
            Some(mut prev) => prev.as_mut().next = node_ref.next,
            None => self.head = node_ref.next,
        }

        match node_ref.next {
            Some(mut next) => next.as_mut().prev = node_ref.prev,
            None => self.tail = node_ref.prev,
        }

        node_ref.prev = None;
        node_ref.next = None;
    }

    /// Add node to front of the list
    unsafe fn add_to_front(&mut self, mut node: NonNull<Node<K, V>>) {
        let node_ref = node.as_mut();

        node_ref.next = self.head;
        node_ref.prev = None;

        if let Some(mut old_head) = self.head {
            old_head.as_mut().prev = Some(node);
        } else {
            // First node, set as tail too
            self.tail = Some(node);
        }

        self.head = Some(node);
    }

    /// Remove the least recently used item - correctly implements LRU eviction
    /// 
Removes from the tail (back) which holds the LRU entry for O(1) eviction

    unsafe fn remove_lru(&mut self) -> Option<K> {
        self.tail.map(|mut tail_node| {
            let tail_ref = tail_node.as_mut();
            let key = tail_ref.key.clone();

            // Remove from doubly-linked list and HashMap for correct LRU eviction
            self.remove_from_list(tail_node);
            self.map.remove(&key);

            // Deallocate the node
            drop(Box::from_raw(tail_node.as_ptr()));

            key
        })
    }

    /// Insert a new node or update existing one
    fn put(&mut self, key: K, value: V, ttl: Option<Duration>) -> CacheResult<()> {
        // Use per-entry TTL override or default TTL for precise expiry control
        let effective_ttl = ttl.or(self.default_ttl);

        // Check if key already exists
        if let Some(&mut existing_node) = self.map.get(&key) {
            unsafe {
                let node_ref = existing_node.as_mut();
                node_ref.value = value;
                // Set per-entry expiration timestamp with precise Instant-based calculation
                node_ref.expires_at = effective_ttl.map(|duration| Instant::now() + duration);
                self.move_to_front(existing_node);
            }
            return Ok(());
        }

        // Create new node
        let new_node = Box::new(Node::new(key.clone(), value, effective_ttl));
        let node_ptr = NonNull::new(Box::into_raw(new_node))
            .ok_or(CacheError::AllocationError)?;

        // Check capacity and evict LRU when capacity exceeded
        if self.map.len() >= self.capacity {
            unsafe {
                self.remove_lru();
            }
        }

        // Insert new node
        self.map.insert(key, node_ptr);
        unsafe {
            self.add_to_front(node_ptr);
        }

        Ok(())
    }

    /// Promote key to most recently used (requires write lock)
    fn promote(&mut self, key: &K) -> CacheResult<()> {
        if let Some(&node) = self.map.get(key) {
            unsafe {
                self.move_to_front(node);
            }
        }
        Ok(())
    }

    /// Get value by key, promoting to most recently used
    fn get(&mut self, key: &K) -> Option<V> 
    where
        V: Clone,
    {
        self.map.get(key).and_then(|&mut node| {
            unsafe {
                let node_ref = node.as_ref();

                // Check if expired - implements immediate lazy expiry check
                if node_ref.is_expired() {
                    // Remove expired entry and deallocate immediately
                    self.map.remove(key);
                    self.remove_from_list(node);
                    drop(Box::from_raw(node.as_ptr()));
                    return None;
                }

                let value = node_ref.value.clone();
                // Promote to most recently used position on access
                self.move_to_front(node);
                Some(value)
            }
        })
    }

    /// Remove expired entries - background eviction with configurable intervals
    fn evict_expired(&mut self) -> usize {
        let mut expired_keys = Vec::new();

        // Collect expired keys
        for (key, &node) in &self.map {
            unsafe {
                if node.as_ref().is_expired() {
                    expired_keys.push(key.clone());
                }
            }
        }

        // Remove expired entries and deallocate nodes
        let count = expired_keys.len();
        for key in expired_keys {
            if let Some(&node) = self.map.get(&key) {
                unsafe {
                    self.map.remove(&key);
                    self.remove_from_list(node);
                    drop(Box::from_raw(node.as_ptr()));
                }
            }
        }

        count
    }

    /// Get cache statistics
    fn stats(&self) -> CacheStats {
        CacheStats {
            size: self.map.len(),
            capacity: self.capacity,
        }
    }
}

impl<K, V> Drop for CacheInner<K, V> {
    fn drop(&mut self) {
        // Clean up all nodes to prevent memory leaks
        let mut current = self.head;
        while let Some(node) = current {
            unsafe {
                let node_ref = node.as_ref();
                current = node_ref.next;
                drop(Box::from_raw(node.as_ptr()));
            }
        }
    }
}

