}

impl<K, V> fmt::Debug for LruCache<K, V>
where
    K: fmt::Debug + Clone + Eq + Hash,
    V: fmt::Debug + Clone,
{
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self.stats() {
            Ok(stats) => {
                f.debug_struct("LruCache")
                    .field("size", &stats.size)
                    .field("capacity", &stats.capacity)
                    .field("poisoned", &false)
                    .finish()
            }
            Err(CacheError::PoisonedLock(_)) => {
                f.debug_struct("LruCache")
                    .field("status", &"poisoned")
                    .field("poisoned", &true)
                    .finish()
            }
            Err(_) => {
                f.debug_struct("LruCache")
                    .field("status", &"error")
                    .field("poisoned", &false)
                    .finish()
            }
        }
    }
}

// Safety: LruCache is safe to send between threads and share references
// because all access to the inner cache goes through RwLock with proper
// poison recovery mechanisms. The generic bounds ensure K and V types
// support safe concurrent access through Send + Sync requirements.
unsafe impl<K, V> Send for LruCache<K, V> 
where
    K: Send + Sync + Clone + Eq + Hash,
    V: Send + Sync + Clone,
{}

unsafe impl<K, V> Sync for LruCache<K, V>
where
    K: Send + Sync + Clone + Eq + Hash,
    V: Send + Sync + Clone,
{}

/// Builder for configuring LRU cache instances
/// 
/// Provides a fluent interface for cache configuration with sensible defaults.
/// Implements comprehensive error checking and validation.
/// 
/// The generic bounds ensure thread safety and proper cache key functionality:
/// - `Clone + Eq + Hash` for key operations in HashMap and doubly-linked list
/// - `Send + Sync + 'static` for safe cross-thread sharing and background eviction
/// 
/// # Example
/// 
/// ```rust
/// use std::time::Duration;
/// 
/// let cache = LruCache::<String, Vec<u8>>::builder()
///     .capacity(1000)
///     .ttl(Duration::from_secs(300))
///     .eviction_interval(Duration::from_secs(60))
///     .build()?;
/// # Ok::<(), Box<dyn std::error::Error>>(())
/// ```
pub struct LruCacheBuilder<K, V> {
    capacity: Option<usize>,
    default_ttl: Option<Duration>,
    eviction_interval: Duration,
    _phantom: std::marker::PhantomData<(K, V)>,
}

impl<K, V> LruCacheBuilder<K, V>
where
    K: Clone + Eq + Hash + Send + Sync + 'static,
    V: Clone + Send + Sync + 'static,
{
    fn new() -> Self {
        Self {
            capacity: None,
            default_ttl: None,
            eviction_interval: Duration::from_secs(60), // Default 1 minute
            _phantom: std::marker::PhantomData,
        }
    }

    /// Set the maximum number of entries in the cache
    /// 
    /// Must be greater than 0. Includes debug assertions for capacity validation.
    pub fn capacity(mut self, capacity: usize) -> Self {
        debug_assert!(capacity > 0, "Cache capacity must be greater than 0");
        self.capacity = Some(capacity);
        self
    }

    /// Set the default TTL for cache entries
    /// 
    /// Individual entries can override this with `put_with_ttl` for per-entry control.
    pub fn ttl(mut self, ttl: Duration) -> Self {
        self.default_ttl = Some(ttl);
        self
    }

    /// Set the interval for background eviction of expired entries
    /// 
    /// Shorter intervals provide more responsive cleanup but use more CPU.
    /// Longer intervals reduce overhead but may allow expired entries to linger.
    pub fn eviction_interval(mut self, interval: Duration) -> Self {
        self.eviction_interval = interval;
        self
    }

    /// Build the cache instance
    /// 
    /// Returns an error if capacity is not set or is zero.
    /// Creates a named background thread for periodic expiry cleanup.
    pub fn build(self) -> CacheResult<LruCache<K, V>> {
        let capacity = self.capacity.ok_or(CacheError::InvalidCapacity)?;

        if capacity == 0 {
            return Err(CacheError::InvalidCapacity);
        }

        let inner = Arc::new(RwLock::new(CacheInner::new(capacity, self.default_ttl)));
        let shutdown_signal = Arc::new(AtomicBool::new(false));

        let background_thread = LruCache::start_background_eviction(
            Arc::clone(&inner),
            Arc::clone(&shutdown_signal),
            self.eviction_interval,
        )?;

        Ok(LruCache {
            inner,
            shutdown_signal,
            background_thread: Some(background_thread),
        })
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::thread;
    use std::time::Duration;

    #[test]
    fn test_basic_operations() {
        let cache = LruCache::builder()
            .capacity(2)
            .build()
            .unwrap();

        // Test put and get
        cache.put("key1".to_string(), 1).unwrap();
        assert_eq!(cache.get(&"key1".to_string()).unwrap(), Some(1));

        // Test capacity eviction
        cache.put("key2".to_string(), 2).unwrap();
        cache.put("key3".to_string(), 3).unwrap(); // Should evict key1

        assert_eq!(cache.get(&"key1".to_string()).unwrap(), None);
        assert_eq!(cache.get(&"key2".to_string()).unwrap(), Some(2));
        assert_eq!(cache.get(&"key3".to_string()).unwrap(), Some(3));

        cache.shutdown();
    }

    #[test]
    fn test_lru_order() {
        let cache = LruCache::builder()
            .capacity(2)
            .build()
            .unwrap();

        cache.put("key1".to_string(), 1).unwrap();
        cache.put("key2".to_string(), 2).unwrap();

        // Access key1 to make it most recently used
        cache.get(&"key1".to_string()).unwrap();

        // Add key3, should evict key2 (least recently used)
        cache.put("key3".to_string(), 3).unwrap();

        assert_eq!(cache.get(&"key1".to_string()).unwrap(), Some(1));
        assert_eq!(cache.get(&"key2".to_string()).unwrap(), None);
        assert_eq!(cache.get(&"key3".to_string()).unwrap(), Some(3));

        cache.shutdown();
    }

    #[test]
    fn test_ttl_expiry() {
        let cache = LruCache::builder()
            .capacity(10)
            .build()
            .unwrap();

        // Insert with short TTL
        cache.put_with_ttl("key1".to_string(), 1, Some(Duration::from_millis(50))).unwrap();

        // Should be available immediately
        assert_eq!(cache.get(&"key1".to_string()).unwrap(), Some(1));

        // Wait for expiry
        thread::sleep(Duration::from_millis(60));

        // Should be expired - tests immediate lazy expiry check on access
        assert_eq!(cache.get(&"key1".to_string()).unwrap(), None);

        cache.shutdown();
    }

    #[test]
    fn test_peek_vs_get() {
        let cache = LruCache::builder()
            .capacity(2)
            .build()
            .unwrap();

        cache.put("key1".to_string(), 1).unwrap();
        cache.put("key2".to_string(), 2).unwrap();

        // Peek at key1 (doesn't promote)
        assert_eq!(cache.peek(&"key1".to_string()).unwrap(), Some(1));

        // Add key3, should evict key1 since peek didn't promote it
        cache.put("key3".to_string(), 3).unwrap();

        assert_eq!(cache.get(&"key1".to_string()).unwrap(), None);
        assert_eq!(cache.get(&"key2".to_string()).unwrap(), Some(2));
        assert_eq!(cache.get(&"key3".to_string()).unwrap(), Some(3));

        cache.shutdown();
    }

    #[test]
    fn test_concurrent_access() {
        let cache = Arc::new(LruCache::builder()
            .capacity(100)
            .build()
            .unwrap());

        let mut handles = Vec::new();

        // Spawn multiple threads
        for i in 0..10 {
            let cache_clone = Arc::clone(&cache);
            let handle = thread::spawn(move || {
                for j in 0..10 {
                    let key = format!("key-{}-{}", i, j);
                    let value = i * 10 + j;

                    cache_clone.put(key.clone(), value).unwrap();
                    assert_eq!(cache_clone.get(&key).unwrap(), Some(value));
                }
            });
            handles.push(handle);
        }

        // Wait for all threads
        for handle in handles {
            handle.join().unwrap();
        }

        cache.shutdown();
    }

    #[test]
    fn test_background_eviction() {
        let cache = LruCache::builder()
            .capacity(10)
            .eviction_interval(Duration::from_millis(10))
            .build()
            .unwrap();

        // Insert entries with short TTL
        for i in 0..5 {
            cache.put_with_ttl(
                format!("key{}", i), 
                i, 
                Some(Duration::from_millis(50))
            ).unwrap();
        }

        // Wait for background eviction
        thread::sleep(Duration::from_millis(100));

        // Entries should be evicted by background thread
        let stats = cache.stats().unwrap();
        assert_eq!(stats.size, 0);

        cache.shutdown();
    }

    #[test]
    fn test_builder_pattern() {
        let cache = LruCache::<String, Vec<u8>>::builder()
            .capacity(1000)
            .ttl(Duration::from_secs(300))
            .eviction_interval(Duration::from_secs(60))
            .build()
            .unwrap();

        cache.put("test".to_string(), b"hello".to_vec()).unwrap();
        assert_eq!(cache.get(&"test".to_string()).unwrap(), Some(b"hello".to_vec()));

        cache.shutdown();
    }

    #[test]
    fn test_error_handling() {
        // Test invalid capacity
        let result = LruCache::<String, i32>::builder()
            .capacity(0)
            .build();
        assert!(matches!(result, Err(CacheError::InvalidCapacity)));

        // Test missing capacity
        let result = LruCache::<String, i32>::builder().build();
        assert!(matches!(result, Err(CacheError::InvalidCapacity)));
    }

    #[test]
    fn test_fine_grained_locking() {
        let cache = Arc::new(LruCache::builder()
            .capacity(10)
            .build()
            .unwrap());

        // Insert some data
        cache.put("key1".to_string(), 1).unwrap();

        // Test that peek doesn't interfere with get operations
        let cache_clone = Arc::clone(&cache);
        let handle = thread::spawn(move || {
            for _ in 0..100 {
                let _ = cache_clone.peek(&"key1".to_string());
            }
        });

        // These operations should proceed without blocking on the peeks
        for i in 0..10 {
            cache.put(format!("key{}", i), i).unwrap();
            assert!(cache.get(&format!("key{}", i)).unwrap().is_some());
        }

        handle.join().unwrap();
        cache.shutdown();
    }
}
```

