### 5.2 Caching Strategy

```go
type CacheLayer struct {
    redis        *redis.Client
    localCache   *bigcache.BigCache
    documentTTL  time.Duration
    operationTTL time.Duration
}

func (c *CacheLayer) GetDocumentState(docID string) (*DocumentState, error) {
    // Try local cache first (L1)
    if state, err := c.getFromLocalCache(docID); err == nil {
        return state, nil
    }

    // Try Redis cache (L2)
    if state, err := c.getFromRedis(docID); err == nil {
        // Populate local cache
        c.setLocalCache(docID, state)
        return state, nil
    }

    // Cache miss - load from database
    return nil, ErrCacheMiss
}

func (c *CacheLayer) InvalidateDocument(docID string) error {
    // Invalidate local cache
    c.localCache.Delete(docID)

    // Invalidate Redis cache
    return c.redis.Del(context.Background(), c.documentKey(docID)).Err()
}

// Cache warming for frequently accessed documents
func (c *CacheLayer) WarmCache(docIDs []string) error {
    for _, docID := range docIDs {
        go func(id string) {
            if state, err := c.loadFromDatabase(id); err == nil {
                c.setRedisCache(id, state)
            }
        }(docID)
    }
    return nil
}
```

### 5.3 Data Consistency Strategy

**Consistency Model:** Eventually Consistent with Strong Consistency for Critical Operations

```go
type ConsistencyManager struct {
    primaryDB   *sql.DB
    replicaDBs  []*sql.DB
    writeQuorum int
    readQuorum  int
}

func (cm *ConsistencyManager) WriteOperation(ctx context.Context, op *Operation) error {
    // Write to primary database
    if err := cm.writeToDatabase(ctx, cm.primaryDB, op); err != nil {
        return fmt.Errorf("primary write failed: %w", err)
    }

    // Async replication to replicas
    go cm.replicateToSecondaries(ctx, op)

    return nil
}

func (cm *ConsistencyManager) ReadWithConsistency(ctx context.Context, docID string, consistency ConsistencyLevel) (*DocumentState, error) {
    switch consistency {
    case StrongConsistency:
        return cm.readFromPrimary(ctx, docID)
    case EventualConsistency:
        return cm.readFromReplica(ctx, docID)
    default:
        return cm.readFromCache(ctx, docID)
    }
}
```

